 public function form(array $ctx):array{$state=$ctx['position_state']??null;$eval=$ctx['policy_evaluation']??null;$decisionAt=$ctx['decision_at']??null;$codes=[];$warnings=[];$blockers=[];$g=[];$matched=$eval['matched_rule']??null;$condition=$eval['state_condition']??null;$type=$eval['candidate_type']??null;$available=is_array($state)&&is_array($eval);$fresh=!is_array($state)||!in_array('POSITION_MARKET_OBSERVATION_STALE',$state['reason_codes']??[],true);$can=$available&&$fresh&&($eval['status']??null)==='matched_reference_rule'&&is_array($matched)&&in_array($type,$this->config['supported_review_candidate_types'],true)&&($state['status']??null)==='condition_observed';foreach([['position_state_available',true,is_array($state),'MANAGED_POSITION_UNAVAILABLE'],['condition_observed',is_array($state),is_array($state)?(($state['status']??null)==='condition_observed'||$condition==='protection_reference_missing'):null,'POSITION_MANAGEMENT_POLICY_NO_CONDITION'],['policy_evaluation_available',true,is_array($eval),'POSITION_MANAGEMENT_POLICY_UNAVAILABLE'],['matched_rule_available',is_array($eval),is_array($matched),'POSITION_MANAGEMENT_POLICY_NO_MATCHING_RULE'],['supported_candidate_type',is_array($eval),$type?in_array($type,$this->config['supported_review_candidate_types'],true):null,'POSITION_MANAGEMENT_CANDIDATE_BLOCKED'],['position_identity_match',$available,true,'POSITION_MANAGEMENT_CANDIDATE_IDENTITY_MISMATCH'],['policy_identity_match',$available,true,'POSITION_MANAGEMENT_CANDIDATE_IDENTITY_MISMATCH'],['evidence_freshness',is_array($state),$fresh,'POSITION_MANAGEMENT_STALE_OBSERVATION_REVIEW_BLOCKED']] as [$n,$e,$pass,$code]){$g[]=$this->gate($n,$e,$pass,$pass===true?'passed':'blocking',$code);if($pass===false)$this->add($codes,$code,$blockers);}if(!$available){$status='unavailable';$elig='position_state_unavailable';$this->add($codes,'POSITION_MANAGEMENT_CANDIDATE_UNAVAILABLE',$blockers);}elseif(!$matched){$status='unavailable';$elig=$condition?'no_matching_rule':'no_con