 public function validateCandidate($r):void{if(($r['schema_version']??null)!==$this->config['candidate_schema_version'])throw new \InvalidArgumentException('bad candidate schema');if(in_array($r['candidate_type']??null,['HOLD','SELL','CUT_LOSS','EXIT_POSITION','UPDATE_STOP','UPDATE_TARGET'],true))throw new \InvalidArgumentException('action candidate forbidden');if(($r['execution']['executable']??null)!==false||($r['execution']['instruction']??null)!==null)throw new \InvalidArgumentException('candidate executable forbidden');if(($r['status']??null)==='policy_hypothesis'&&!preg_match('/^[a-f0-9]{64}$/',$r['candidate_id']??''))throw new \InvalidArgumentException('bad candidate id');if(count($r['reason_codes'])!==count(array_unique($r['reason_codes'])))throw new \InvalidArgumentException('duplicate candidate reasons');}
